[DataContractAttribute,SysOperationContractProcessingAttribute(classStr(ETG_SalesAgreementVersionCompareUIBuilder))]
class ETG_SalesAgreementVersionCompareContract implements SysOperationValidatable
{
    SalesAgreementId            salesAgreementId;
    //List                        confimationFirst;
    str                         confimationFirst,ConfirmationSecond;
    NoYesId                     isSalesAgreement;

}

Method.Source:
public boolean validate()
{
    boolean ret = true;
    if (!confimationFirst)
    {
        ret = checkFailed("First version mandatory");
    }
    if(!ConfirmationSecond)
    {
        ret = checkFailed("Second version mandatory");
    }
    if(confimationFirst == ConfirmationSecond)
    {
        ret = checkFailed("Same value should not select in First and Second version");
    }
    return ret;
}

[DataMemberAttribute('Agreement'),
    SysOperationLabelAttribute(literalStr("Agreement")),
    SysOperationDisplayOrderAttribute('1')]
public SalesAgreementId parmAgreementId(SalesAgreementId _salesAgreementId = salesAgreementId)
{
    salesAgreementId = _salesAgreementId;
    return salesAgreementId;
}

[DataMemberAttribute('FirstVersion'),
    SysOperationLabelAttribute(literalStr("First version")),
    SysOperationDisplayOrderAttribute('2')]
public str parmConfirmationFirst(str _confimationFirst = confimationFirst)
{
    confimationFirst = _confimationFirst;
    return confimationFirst;
}

[DataMemberAttribute('SecondVersion'),
    SysOperationLabelAttribute(literalStr("Second version")),
    SysOperationDisplayOrderAttribute('3')]
public str parmConfirmationSecond(str _ConfirmationSecond = ConfirmationSecond)
{
    ConfirmationSecond = _ConfirmationSecond;
    return ConfirmationSecond;
}

[DataMemberAttribute('IsSalesAgreement'),
    SysOperationLabelAttribute(literalStr("Is sales agreement")),
    SysOperationDisplayOrderAttribute('3')]
public NoYesId parmIsSalesAgreement(NoYesId _isSalesAgreement = isSalesAgreement)
{
    isSalesAgreement = _isSalesAgreement;
    return isSalesAgreement;
}
